('mb_page.eyebrow',        'en', 'Memory Book & Care Book'),
('mb_page.hero_title',     'en', 'Everything your care team needs — in one place'),
('mb_page.hero_body',      'en', 'When a new caregiver walks in, they should not have to guess. The Memory Book captures who your loved one is, what they need, and what brings them comfort. The Care Book keeps every household detail — insurance, finances, providers, and more — organised and accessible. Together, they cover every dimension of confident caregiving.'),
('mb_page.mock_tab_daily',     'en', 'Daily Living'),
('mb_page.mock_tab_household', 'en', 'Household'),
('mb_page.benefits_title',    'en', 'Why families rely on Memory Book & Care Book'),
('mb_page.benefits_subtitle', 'en', 'Two tools, one care team. Everything documented once — available to everyone the moment they join.'),
('mb_page.benefit1_title',    'en', 'Instant care context'),
('mb_page.benefit1_body',     'en', 'Any new caregiver — a respite worker, a sibling visiting from abroad — walks in with everything they need to provide good care from the first moment.'),
('mb_page.benefit2_title',    'en', 'No more searching'),
('mb_page.benefit2_body',     'en', 'Every contact, provider, insurance policy, and utility account in one place. Find the right number in seconds, not minutes.'),
('mb_page.benefit3_title',    'en', 'Safer handovers'),
('mb_page.benefit3_body',     'en', 'Medical notes, allergies, daily living independence levels, and care considerations are always on hand. Informed transitions mean fewer gaps and fewer risks.'),
('mb_page.benefit4_title',    'en', 'Personal dignity'),
('mb_page.benefit4_body',     'en', 'Beyond clinical facts, the Memory Book captures the person — their story, their preferences, what brings them joy. Care becomes more than task completion.'),
('mb_page.benefit5_title',    'en', 'Household continuity'),
('mb_page.benefit5_body',     'en', 'The Care Book means a caregiver stepping in during a crisis can find the insurance card, call the right plumber, and manage bills — without burdening the family.'),
('mb_page.features_title',    'en', 'Two tools. A complete picture.'),
('mb_page.features_subtitle', 'en', 'The Memory Book covers who your loved one is and how to care for them. The Care Book covers everything that keeps their household running.'),
('mb_page.pillar_mb_label',    'en', 'Memory Book'),
('mb_page.pillar_mb_heading',  'en', 'The personal care profile'),
('mb_page.pillar_mb_body',     'en', 'A living record of who your loved one is — their identity, their care network, their medical context, how they manage daily tasks, and what brings them comfort.'),
('mb_page.feat_identity_title', 'en', 'Identity & Personal Profile'),
('mb_page.feat_identity_body',  'en', 'Capture who your loved one is — not just their name, but their story. This section helps every caregiver connect with the person behind the care plan.'),
('mb_page.feat_identity_f1',    'en', 'Preferred name and how they like to be addressed'),
