('mb_page.pillar_cb_label',   'en', 'Care Book'),
('mb_page.pillar_cb_heading', 'en', 'The household & logistics record'),
('mb_page.pillar_cb_body',    'en', 'A structured record of every practical detail that keeps your loved one''s household running — insurance policies, finances, vehicles, subscriptions, home service providers, and online accounts.'),
('mb_page.feat_insurance_title', 'en', 'Insurance Policies'),
