('mb_page.feat_providers_f1',    'en', 'Electricity, water, gas, and waste removal'),
('mb_page.feat_providers_f2',    'en', 'Internet, home phone, and mobile'),
('mb_page.feat_providers_f3',    'en', 'Plumber, electrician, HVAC, and lawn care'),
('mb_page.feat_providers_f4',    'en', 'Pest control, handyman, and other maintenance contacts'),
('mb_page.feat_vehicles_title', 'en', 'Vehicles & Vehicle Care'),
('mb_page.feat_vehicles_body',  'en', 'Track vehicles and the service providers who maintain them — with automatic alerts when registration is due.'),
('mb_page.feat_vehicles_f1',    'en', 'Make, model, year, and licence plate'),
('mb_page.feat_vehicles_f2',    'en', 'Registration due date with auto-alerts at 60 days'),
('mb_page.feat_vehicles_f3',    'en', 'Parking location and service provider'),
('mb_page.feat_vehicles_f4',    'en', 'Oil change, tires, brakes, inspection, and dealer contacts'),
('mb_page.feat_subs_title', 'en', 'Subscriptions & Online Accounts'),
('mb_page.feat_subs_body',  'en', 'A clear record of streaming services, software licences, and online accounts — so nothing is forgotten and nothing auto-renews unexpectedly.'),
('mb_page.feat_subs_f1',    'en', 'Streaming, music, and news subscriptions'),
('mb_page.feat_subs_f2',    'en', 'Health & wellness, delivery, and utility services'),
('mb_page.feat_subs_f3',    'en', 'Social media, email, and cloud storage accounts'),
('mb_page.feat_subs_f4',    'en', '20+ platform suggestions for quick entry'),
('mb_page.access_title', 'en', 'Built for the team. Visible to everyone.'),
('mb_page.access_body',  'en', 'The team owner builds and maintains both the Memory Book and the Care Book. Every caregiver you invite — family members, in-home workers, or support people — can view them the moment they join, with no setup required. The Finances section remains owner-only for privacy.'),
('mb_page.access_cta',   'en', 'Start Your Free Account'),
('mb_page.access_plans', 'en', 'View Plans & Pricing'),
('mb_page.personas_title',    'en', 'Who benefits'),
('mb_page.personas_subtitle', 'en', 'From the overnight carer arriving for the first time to a sibling managing a crisis from overseas.'),
('mb_page.persona1_title',    'en', 'The overnight respite carer'),
('mb_page.persona1_quote',    'en', '"I used to dread covering for a family I didn''t know. Now I check the Memory Book before I arrive."'),
('mb_page.persona1_b1',       'en', 'Knows preferred routines, bedtime comforts, and communication style before walking in'),
('mb_page.persona1_b2',       'en', 'Can find emergency contacts without waking anyone up'),
('mb_page.persona1_b3',       'en', 'Understands medication needs and daily living support levels from the first night'),
('mb_page.persona2_title',    'en', 'The sibling managing from overseas'),
('mb_page.persona2_quote',    'en', '"I visit twice a year and felt like a stranger. The Memory Book and Care Book close that gap."'),
('mb_page.persona2_b1',       'en', 'Catches up on medical and daily living context without a long family debrief'),
('mb_page.persona2_b2',       'en', 'Finds insurance, utilities, and provider contacts to handle logistics remotely'),
('mb_page.persona2_b3',       'en', 'Knows what Mum enjoys now — and what to avoid — before every visit'),
('mb_page.persona3_title',    'en', 'The primary caregiver'),
('mb_page.persona3_quote',    'en', '"I am the memory bank. These tools mean I don''t have to explain everything every time."'),
('mb_page.persona3_b1',       'en', 'Documents everything once — not a dozen times across texts and phone calls'),
('mb_page.persona3_b2',       'en', 'Shares the care burden without losing control of accuracy'),
('mb_page.persona3_b3',       'en', 'Reduces the emotional load of constant communication and repeated handovers'),
('mb_page.persona4_title',    'en', 'The family member handling a care transition'),
('mb_page.persona4_quote',    'en', '"Dad had a fall. I had to make a dozen decisions in hours. The Care Book meant I had the answers."'),
('mb_page.persona4_b1',       'en', 'Insurance details and healthcare providers available immediately'),
('mb_page.persona4_b2',       'en', 'Utility and maintenance contacts on hand for managing the household remotely'),
('mb_page.persona4_b3',       'en', 'Medical context and emergency contacts accessible to every family member in the room'),
('mb_page.faq_title',    'en', 'Frequently Asked Questions'),
('mb_page.faq_subtitle', 'en', 'Common questions about the Memory Book and Care Book features.'),
('mb_page.faq1_q', 'en', 'What is the Memory Book and who can see it?'),
('mb_page.faq1_a', 'en', 'The Memory Book is a structured care profile for your loved one covering identity, contacts, medical context, daily living independence levels, and personal preferences. The team owner builds and updates it. Every caregiver you invite can view it instantly — no separate setup required.'),
('mb_page.faq2_q', 'en', 'What is the Care Book?'),
('mb_page.faq2_a', 'en', 'The Care Book is the household and logistics companion to the Memory Book. It stores insurance policies, financial accounts, auto-pay bills, subscriptions, home service providers, vehicles, vehicle care contacts, and online accounts — all in one organised place. It is included in the same plan as the Memory Book.'),
('mb_page.faq3_q', 'en', 'Which plan includes the Memory Book and Care Book?'),
('mb_page.faq3_a', 'en', 'Both tools are available on the Primary Caregiver and Family Circle plans. The Family Circle plan is designed for teams — up to 3 caregivers sharing a single Memory Book and Care Book, with all team members able to view both the moment they join.'),
('mb_page.faq4_q', 'en', 'Can team members edit the Memory Book or Care Book?'),
('mb_page.faq4_a', 'en', 'Currently, only the team owner can create and edit entries. All other team members have read-only access to the Memory Book and Care Book (except the Finances section, which is owner-only). This keeps the records accurate with one person responsible for updates.'),
('mb_page.faq5_q', 'en', 'Is the Memory Book a medical record?'),
('mb_page.faq5_a', 'en', 'No. The Memory Book is a practical caregiving reference — not a clinical document. It captures information that helps caregivers provide safe, informed, and personal care. For formal medical records, please refer to your loved one''s healthcare providers.'),
('mb_page.faq6_q', 'en', 'Who can see the Finances section?'),
('mb_page.faq6_a', 'en', 'The Finances section is visible only to the team owner. Team members who join your care team can see all other sections of the Care Book, but the Finances section is kept private to protect sensitive financial information.'),
('mb_page.faq7_q', 'en', 'Is my loved one''s information private and secure?'),
('mb_page.faq7_a', 'en', 'Yes. All information is only visible to members of your care team — people you have explicitly invited. It is stored securely on encrypted infrastructure. CarerView never shares your data with third parties and you retain full ownership of everything you enter.'),
('mb_page.faq8_q', 'en', 'Can I print the Memory Book?'),
('mb_page.faq8_a', 'en', 'Yes. The team owner can print a formatted version of the Memory Book from the Overview tab. This is useful for appointments, hospital visits, or providing a physical copy to a new in-home carer.'),
('mb_page.cta_title', 'en', 'Start building your loved one''s Memory Book and Care Book today'),
('mb_page.cta_body',  'en', 'Create a free account and explore CarerView — or choose a paid plan to unlock both the Memory Book and Care Book and share them with your care team.')

